```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Serialize packet_id
        stream.serialise(packet_id);

        // Serialize username with length prefix
        stream.serialise(static_cast<uint32_t>(username.size()));
        if (!username.empty()) {
            stream.serialise(username.data(), username.size());
        }

        // Serialize scores vector with count prefix
        stream.serialise(static_cast<uint32_t>(scores.size()));
        for (auto score : scores) {
            stream.serialise(score);
        }

        // Serialize metadata as null-terminated string
        stream.serialise(metadata.c_str(), metadata.size() + 1); // +1 for null terminator
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    hexi::output_stream stream;

    // Create a non-const copy for serialization
    NetworkPacket packet_copy = packet;
    packet_copy.serialise(stream);

    return stream.buffer();
}
```

