bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create buffer adaptor
    hexi::buffer_adaptor adaptor(buffer);

    // Calculate required space: header (4 bytes) + vector size (4 bytes) + each item (4 bytes each)
    const size_t required_space = sizeof(uint32_t) + sizeof(uint32_t) + (items.size() * sizeof(uint32_t));

    // Check available space
    if (adaptor.available() < required_space) {
        return false; // Insufficient space
    }

    // Get write pointer
    uint8_t* write_ptr = adaptor.write_ptr();

    // Create binary stream
    hexi::binary_stream stream(write_ptr, adaptor.available());

    // Write header
    stream << header;

    // Write container (vector of items)
    // write_container writes the size first, then each element
    stream.write_container(items);

    // Commit the written data
    adaptor.commit(stream.written_bytes());

    return true;
}
