    EXPECT_EQ(1, preview1[0]);
    EXPECT_EQ(2, preview1[1]);
    EXPECT_EQ(3, preview1[2]);

    // Both previews should be the same (read pointer not advanced)
    EXPECT_EQ(preview1, preview2);

    // Buffer size should remain unchanged
    EXPECT_EQ(test_data.size(), storage.size());
