#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Get the current readable size
    size_t readable_size = storage.readable_size();

    // Adjust bytes_to_preview to not exceed available data
    if (bytes_to_preview > readable_size) {
        bytes_to_preview = readable_size;
    }

    // Create result vector
    std::vector<uint8_t> result(bytes_to_preview);

    // Use peek to copy data without consuming/advancing read pointer
    if (bytes_to_preview > 0) {
        storage.peek(result.data(), bytes_to_preview);
    }

    return result;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status;
    status.readable_size = storage.readable_size();
    status.free_space = storage.capacity() - status.readable_size;
    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    storage.reset();
}

