```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Open file in read mode
    hexi::file_buffer file(file_path, "rb");

    // Get available data size (don't read beyond file size)
    size_t available_size = file.size();
    size_t actual_read_size = (bytes_to_read > available_size) ? available_size : bytes_to_read;

    // Read data into vector
    std::vector<uint8_t> data(actual_read_size);
    if (actual_read_size > 0) {
        file.read(reinterpret_cast<char*>(data.data()), actual_read_size);
    }

    return data;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Open file in read mode
    hexi::file_buffer file(file_path, "rb");

    // Get current position and available data size
    size_t current_pos = file.tell();
    size_t available_size = file.size() - current_pos;
    size_t actual_preview_size = (bytes_to_preview > available_size) ? available_size : bytes_to_preview;

    // Preview data without advancing pointer
    std::vector<uint8_t> data(actual_preview_size);
    if (actual_preview_size > 0) {
        // Read data temporarily
        file.read(reinterpret_cast<char*>(data.data()), actual_preview_size);
        // Reset position back to original
        file.seek(current_pos);
    }

    return data;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Open file in write mode (creates file if it doesn't exist)
    hexi::file_buffer file(file_path, "wb");

    // Write data to file
    if (!data.empty()) {
        file.write(reinterpret_cast<const char*>(data.data()), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Open file in read mode
    hexi::file_buffer file(file_path, "rb");

    // Return the total size of readable data
    return file.size();
}
