template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_preview) {
    // Get the number of bytes currently available in the buffer
    size_t available_bytes = buffer.size();

    // Determine how many bytes we can actually preview (minimum of requested and available)
    size_t bytes_to_copy = std::min(bytes_to_preview, available_bytes);

    // Create a vector to hold the previewed data
    std::vector<uint8_t> preview_data;
    preview_data.reserve(bytes_to_copy);

    // Copy data from the buffer without advancing the read pointer
    for (size_t i = 0; i < bytes_to_copy; ++i) {
        // Access data at position i without modifying read pointer
        std::byte data_byte = buffer[i];
        preview_data.push_back(static_cast<uint8_t>(data_byte));
    }

    return preview_data;
}
```

