```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Handle negative values using zigzag encoding
    typename std::make_unsigned<T>::type unsigned_value;
    if (value < 0) {
        // Zigzag encoding for negative numbers: (n << 1) ^ (n >> (sizeof(T)*8 - 1))
        unsigned_value = (static_cast<typename std::make_unsigned<T>::type>(-value) << 1) - 1;
    } else {
        unsigned_value = static_cast<typename std::make_unsigned<T>::type>(value) << 1;
    }

    // Encode the unsigned value using varint
    do {
        uint8_t byte = unsigned_value & 0x7F;
        unsigned_value >>= 7;

        if (unsigned_value != 0) {
            byte |= 0x80; // Set continuation bit
        }

        writer.write(byte);
        bytes_written++;
    } while (unsigned_value != 0);

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    typename std::make_unsigned<T>::type unsigned_value = 0;
    int shift = 0;

    while (true) {
        uint8_t byte = reader.read<uint8_t>();
        unsigned_value |= static_cast<typename std::make_unsigned<T>::type>(byte & 0x7F) << shift;
        shift += 7;

        if ((byte & 0x80) == 0) {
            break;
        }
    }

    // Zigzag decoding
    if (unsigned_value & 1) {
        // Negative number
        return -static_cast<T>((unsigned_value + 1) >> 1);
    } else {
        // Positive number
        return static_cast<T>(unsigned_value >> 1);
    }
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);
    hexi::pmc::binary_stream_writer writer(adaptor);

    // Encode the value
    encode_varint<T>(writer, original_value);

    // Create a reader from the buffer
    hexi::pmc::buffer_adaptor read_adaptor(buffer);
    hexi::pmc::binary_stream_reader reader(read_adaptor);

    // Decode the value
    T decoded_value = decode_varint<T>(reader);

    // Check if we decoded the entire buffer
    bool fully_consumed = reader.eof();

    return (original_value == decoded_value) && fully_consumed;
}
```

This implementation provides:

1. **`encode_varint`**: Uses zigzag encoding to handle both positive and negative integers efficiently, then encodes them using the standard varint scheme where each byte contains 7 bits of data and 1 continuation bit.

2. **`decode_varint`**: Reads bytes from the stream, reconstructs the zigzag-encoded value, and then converts it back to the original signed integer.

3. **`encode_decode_roundtrip`**: Encodes a value, then decodes it and verifies that the result matches the original input and that the entire buffer was consumed.

The implementation uses zigzag encoding to efficiently handle negative numbers in varint format, which ensures that small negative numbers are encoded with few bytes, similar to small positive numbers.

