Here's the complete implementation of the functions using the Hexi library:

```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer with enough space for the input data
    std::vector<uint8_t> buffer(input_data.size());

    // Create buffer_write_adaptor for writing
    hexi::pmc::buffer_write_adaptor write_adaptor(buffer.data(), buffer.size());

    // Check available space before writing
    if (write_adaptor.free() >= input_data.size()) {
        // Write data to the buffer
        write_adaptor.write(input_data.data(), input_data.size());
    }

    // Create buffer_read_adaptor for reading
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer.data(), buffer.size());

    // Check readable size
    std::vector<uint8_t> output_data;
    std::size_t readable_size = read_adaptor.size();
    if (readable_size > 0) {
        output_data.resize(readable_size);
        // Read data back from the buffer
        read_adaptor.read(output_data.data(), readable_size);
    }

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create buffer_read_adaptor with the provided buffer data
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer_data.data(), buffer_data.size());

    std::vector<uint8_t> peeked_data;

    // Get the current read pointer position
    const uint8_t* read_ptr = read_adaptor.read_ptr();

    // Determine how much data we can actually peek (min of requested size and available size)
    std::size_t actual_peek_size = std::min(peek_size, read_adaptor.size());

    if (actual_peek_size > 0) {
        // Use copy() to peek at data without advancing the read pointer
        peeked_data.resize(actual_peek_size);
        read_adaptor.copy(peeked_data.data(), actual_peek_size);

        // Now actually read/consume the data to advance the read pointer
        read_adaptor.read(actual_peek_size);
    }

    return peeked_data;
}
