```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer write adaptor
    hexi::pmc::buffer_write_adaptor writer;

    std::size_t total_written = 0;

    // Write each chunk with free space checking
    for (const auto& chunk : chunks) {
        // Check available space before writing
        std::size_t free_space = writer.free();

        // Only write if there's enough space
        if (free_space >= chunk.size()) {
            writer.write(chunk.data(), chunk.size());
            total_written += chunk.size();
        }
    }

    return total_written;
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a buffer read adaptor from the input buffer
    hexi::pmc::buffer_read_adaptor reader(buffer.data(), buffer.size());

    std::vector<uint8_t> result;

    // Read data in chunks until buffer is empty
    while (reader.size() > 0) {
        // Determine how much to read in this iteration
        std::size_t bytes_to_read = std::min(chunk_size, reader.size());

        // Create temporary buffer for reading
        std::vector<uint8_t> temp_buffer(bytes_to_read);

        // Read the data
        reader.read(temp_buffer.data(), bytes_to_read);

        // Append to result
        result.insert(result.end(), temp_buffer.begin(), temp_buffer.end());

        // Check remaining data size after read
        std::size_t remaining = reader.size();
    }

    return result;
}
```

