Here's the complete implementation of the functions using the Hexi library:

```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>
#include <stdexcept>

struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create a buffer read adaptor
    auto adaptor = hexi::pmc::buffer_read_adaptor(buffer);

    // Use read_ptr() to get pointer to current position
    const uint8_t* ptr = adaptor.read_ptr();

    // Verify we have enough data for the header
    if (buffer.size() < sizeof(Header)) {
        throw std::runtime_error("Buffer too small for header");
    }

    // Use copy() to peek at header without advancing read cursor
    Header header;
    adaptor.copy(&header, sizeof(Header));

    // Verify the pointer position hasn't changed
    const uint8_t* ptr_after = adaptor.read_ptr();
    if (ptr != ptr_after) {
        throw std::runtime_error("Read cursor advanced during peek");
    }

    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    // Create a buffer read adaptor
    auto adaptor = hexi::pmc::buffer_read_adaptor(buffer);

    // Use copy() to peek at first byte
    uint8_t first_byte;
    adaptor.copy(&first_byte, 1);

    // Based on the peeked value, decide whether to read more data
    if (first_byte == 0xFF) {
        // If first byte is 0xFF, read the entire remaining data
        std::vector<uint8_t> result(buffer.size());
        adaptor.read(result.data(), result.size());
        return result;
    } else if (first_byte >= 0x80) {
        // If first byte >= 0x80, read 4 bytes
        std::vector<uint8_t> result(4);
        adaptor.read(result.data(), 4);
        return result;
    } else {
        // Otherwise, read just the first byte using read()
        std::vector<uint8_t> result(1);
        adaptor.read(result.data(), 1);
        return result;
    }
}
```

