#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <span>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Write sensor_id directly
        adaptor.write(sensor_id);

        // Write temperatures count first
        uint32_t count = static_cast<uint32_t>(temperatures.size());
        adaptor.write(count);

        // Convert and write each temperature value
        for (const auto& temp : temperatures) {
            float little_endian_temp = hexi::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor.write(little_endian_temp);
        }

        // Convert and write pressure value
        double little_endian_pressure = hexi::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.write(little_endian_pressure);
    }

    void serialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor.read(sensor_id);

        // Read temperatures count first
        uint32_t count;
        adaptor.read(count);

        // Resize vector and read temperature values
        temperatures.resize(count);
        for (auto& temp : temperatures) {
            adaptor.read(temp);
            hexi::little_to_native_inplace(temp);
        }

        // Read pressure value and convert
        adaptor.read(pressure);
        hexi::little_to_native_inplace(pressure);
    }
};

